import { _decorator, Component, Node } from 'cc';
import { mEmitter } from './mEmitter';
import { GameState } from './Constants';
const { ccclass, property } = _decorator;

@ccclass('GameManager')
export class GameManager extends Component {

    private currentState: string;

    private layerMap: Map<string, Node> = new Map();

    @property
    lobbyLayer: any;

    @property(Node)
    popup: Node;

    @property(Node)
    stageLayer: Node;

    protected onLoad(): void {
        new mEmitter();
        this.initState()
    }

    start() {
        console.log(this.layerMap)
    }

    update(deltaTime: number) {

    }

    initState(){
        this.currentState = GameState.LOBBY;
        this.layerMap.set(GameState.LOBBY, this.lobbyLayer);
        this.layerMap.set(GameState.PLAYING, this.stageLayer);
        this.layerMap.set(GameState.POPUP, this.popup);
        
        Array.from(this.layerMap.values()).forEach((layer: Node) => {
            layer.active = false;
        })
        this.showLayer(this.currentState, true);
    }

    showLayer(layerName: string, state: boolean) {
        this.layerMap.get(layerName).active = state;
    }
  
}

